1	//! File discovery for Claude Code session JSONL files.
2	//!
3	//! Scans `~/.claude/projects/` for session files and resolves agent parentage.
4	
5	use serde::{Deserialize, Serialize};
6	use std::collections::HashMap;
7	use std::fs;
8	use std::io::{self, BufRead, BufReader};
9	use std::path::{Path, PathBuf};
10	
11	/// Metadata about a session JSONL file on disk.
12	#[derive(Debug, Clone)]
13	pub struct SessionFile {
14	    /// The session identifier (UUID for main sessions, `agent-<id>` for agents).
15	    pub session_id: String,
16	    /// The project directory name (e.g., `-Users-loki-myproject`).
17	    pub project: Option<String>,
18	    /// Full path to the JSONL file.
19	    pub path: PathBuf,
20	    /// Whether this is an agent file (vs. a main session file).
21	    pub is_agent: bool,
22	    /// The parent session ID for agent files.
23	    pub parent_session_id: Option<String>,
24	}
25	
26	/// Metadata about a sub-agent, loaded from `.meta.json` sidecar files.
27	#[derive(Debug, Clone, Deserialize, Serialize)]
28	#[serde(rename_all = "camelCase")]
29	pub struct AgentMeta {
30	    /// The type of agent (e.g., "code", "research").
31	    pub agent_type: Option<String>,
32	    /// A human-readable description of the agent's task.
33	    pub description: Option<String>,
34	    /// The worktree path associated with this agent, if any.
35	    pub worktree_path: Option<String>,
36	}
37	
38	/// Check if a string looks like a UUID (8-4-4-4-12 hex pattern).
39	fn is_uuid(s: &str) -> bool {
40	    let parts: Vec<&str> = s.split('-').collect();
41	    if parts.len() != 5 {
42	        return false;
43	    }
44	    let expected_lens = [8, 4, 4, 4, 12];
45	    parts
46	        .iter()
47	        .zip(expected_lens.iter())
48	        .all(|(part, &len)| part.len() == len && part.chars().all(|c| c.is_ascii_hexdigit()))
49	}
50	
51	/// Scan `~/.claude/projects/` for all session JSONL files and return metadata.
52	///
53	/// Finds three kinds of files:
54	/// 1. Main sessions: `<project>/<uuid>.jsonl`
55	/// 2. Legacy agents: `<project>/agent-<id>.jsonl`
56	/// 3. New-style agents: `<project>/<uuid>/subagents/agent-<id>.jsonl`
57	pub fn scan_sessions(claude_home: &Path) -> io::Result<Vec<SessionFile>> {
58	    let projects_dir = claude_home.join("projects");
59	    if !projects_dir.is_dir() {
60	        return Ok(Vec::new());
61	    }
62	
63	    let mut results = Vec::new();
64	
65	    let project_entries = fs::read_dir(&projects_dir)?;
66	
67	    for project_entry in project_entries {
68	        let project_entry = project_entry?;
69	        let project_path = project_entry.path();
70	        if !project_path.is_dir() {
71	            continue;
72	        }
73	        let project_name = project_entry.file_name().to_string_lossy().into_owned();
74	
75	        let entries = fs::read_dir(&project_path)?;
76	
77	        for entry in entries {
78	            let entry = entry?;
79	            let entry_path = entry.path();
80	            let file_name = entry.file_name().to_string_lossy().into_owned();
81	
82	            if entry_path.is_file() {
83	                if !file_name.ends_with(".jsonl") {
84	                    continue;
85	                }
86	
87	                let stem = file_name.trim_end_matches(".jsonl");
88	
89	                if is_uuid(stem) {
90	                    // Type 1: Main session — <project>/<uuid>.jsonl
91	                    results.push(SessionFile {
92	                        session_id: stem.to_string(),
93	                        project: Some(project_name.clone()),
94	                        path: entry_path,
95	                        is_agent: false,
96	                        parent_session_id: None,
97	                    });
98	                } else if stem.starts_with("agent-") {
99	                    // Type 2: Legacy agent — <project>/agent-<id>.jsonl
100	                    results.push(SessionFile {
101	                        session_id: stem.to_string(),
102	                        project: Some(project_name.clone()),
103	                        path: entry_path,
104	                        is_agent: true,
105	                        parent_session_id: None,
106	                    });
107	                }
108	            } else if entry_path.is_dir() {
109	                // Skip well-known non-session directories
110	                if file_name == "memory" || file_name == "tool-results" {
111	                    continue;
112	                }
113	
114	                // Check for new-style agents under <uuid>/subagents/
115	                if is_uuid(&file_name) {
116	                    let parent_uuid = file_name.clone();
117	                    let subagents_dir = entry_path.join("subagents");
118	                    if subagents_dir.is_dir() {
119	                        let sub_entries = fs::read_dir(&subagents_dir)?;
120	
121	                        for sub_entry in sub_entries {
122	                            let sub_entry = sub_entry?;
123	                            let sub_path = sub_entry.path();
124	                            let sub_name = sub_entry.file_name().to_string_lossy().into_owned();
125	
126	                            if !sub_path.is_file() || !sub_name.ends_with(".jsonl") {
127	                                continue;
128	                            }
129	
130	                            let sub_stem = sub_name.trim_end_matches(".jsonl");
