// SessionData 重组：去 agent_turns，加 subagents + 三个三态子集合 + capabilities：
pub struct SessionData {
    pub session_id: String,
    pub project: Option<String>,
    pub turns: Vec<ValidatedTurn>,            // 主 session
    pub subagents: Vec<Subagent>,             // 重组：每个 subagent 内嵌自己的 turns
    pub plugins: Option<Vec<PluginUsage>>,    // None=数据不可知；Some([])=确认没用；Some([..])=用了
    pub skills:  Option<Vec<SkillUsage>>,
    pub hooks:   Option<Vec<HookUsage>>,
    pub capabilities: RecordedCapabilities,   // 显式标记 — 用于跨 session 分析的能力分组
    pub first_timestamp: Option<DateTime<Utc>>,
    pub last_timestamp: Option<DateTime<Utc>>,
    pub version: Option<String>,
    pub quality: DataQuality,
    pub metadata: SessionMetadata,
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RecordedCapabilities {
    /// 该 session 的 Claude Code 版本是否记录 attribution_plugin/skill (>= 2.1.138)
    pub plugins: bool,
    pub skills: bool,
    /// 该 session 的版本是否记录 hookCount/hookInfos (>= 2.1.104)
    pub hooks: bool,
}

