            "agentSetting": "custom-agent-definition"
        }"#;
        let entry: Entry = serde_json::from_str(json).unwrap();
        match entry {
            Entry::AgentSetting(asetting) => {
                assert_eq!(asetting.session_id.as_deref(), Some("sess-008"));
